// // This module implements a simple power gating control logic. It takes an enable signal and two inputs A and B, and outputs Y. When enable is high, Y is the logical OR of A and B. When enable is low, Y is 1, indicating that power is gated on.
module power_gating(  
    input wire enable,  
    input wire A,  
    input wire B,  
    output wire Y  
);  
    assign Y = (enable) ? (A & B) : 0;  
endmodule
